#!/usr/bin/env bash
# Generated by bun-bench Harbor export adapter. Oracle reference solution.
# Overwrites the starter source under /app with the bun-bench reference.
set -euo pipefail

mkdir -p /app/src
cat > /app/src/server.ts <<'BUN_BENCH_SOLUTION_EOF'
const port = Number(Bun.env.PORT ?? 3000);

type Item = { id: number; label: string };

// Kept sorted ascending by id (ids are assigned monotonically, so push keeps it sorted).
const items: Item[] = [];
let nextId = 1;

function encodeCursor(id: number): string {
  return Buffer.from(String(id), "utf8").toString("base64url");
}

function decodeCursor(token: string): number | null {
  let decoded: string;
  try {
    decoded = Buffer.from(token, "base64url").toString("utf8");
  } catch {
    return null;
  }
  if (!/^\d+$/.test(decoded)) return null;
  const value = Number(decoded);
  if (!Number.isInteger(value) || value <= 0) return null;
  return value;
}

function parseLimit(raw: string | null): number | null {
  if (raw === null) return 10;
  if (!/^-?\d+$/.test(raw.trim())) return null;
  const value = Number(raw);
  if (!Number.isInteger(value) || value <= 0) return null;
  return Math.min(value, 100);
}

Bun.serve({
  port,
  async fetch(request) {
    const url = new URL(request.url);

    if (request.method === "POST" && url.pathname === "/items") {
      let body: unknown;
      try {
        body = await request.json();
      } catch {
        return Response.json({ error: "invalid_body" }, { status: 422 });
      }
      const record = body as Record<string, unknown> | null;
      if (!record || typeof record.label !== "string") {
        return Response.json({ error: "invalid_body" }, { status: 422 });
      }
      const item: Item = { id: nextId++, label: record.label };
      items.push(item);
      return Response.json(item, { status: 201 });
    }

    if (request.method === "GET" && url.pathname === "/items") {
      const limit = parseLimit(url.searchParams.get("limit"));
      if (limit === null) {
        return Response.json({ error: "invalid_limit" }, { status: 400 });
      }

      const afterParam = url.searchParams.get("after");
      const beforeParam = url.searchParams.get("before");
      if (afterParam !== null && beforeParam !== null) {
        return Response.json({ error: "invalid_cursor_combination" }, { status: 400 });
      }

      let after: number | null = null;
      let before: number | null = null;
      if (afterParam !== null) {
        after = decodeCursor(afterParam);
        if (after === null) return Response.json({ error: "invalid_cursor" }, { status: 400 });
      }
      if (beforeParam !== null) {
        before = decodeCursor(beforeParam);
        if (before === null) return Response.json({ error: "invalid_cursor" }, { status: 400 });
      }

      let page: Item[];
      if (before !== null) {
        // Highest-id slice strictly below the cursor, returned ascending.
        const below = items.filter((it) => it.id < before!);
        page = below.slice(Math.max(0, below.length - limit));
      } else if (after !== null) {
        page = items.filter((it) => it.id > after!).slice(0, limit);
      } else {
        page = items.slice(0, limit);
      }

      let start_cursor: string | null = null;
      let end_cursor: string | null = null;
      let has_next = false;
      let has_prev = false;
      if (page.length > 0) {
        const firstId = page[0]!.id;
        const lastId = page[page.length - 1]!.id;
        start_cursor = encodeCursor(firstId);
        end_cursor = encodeCursor(lastId);
        has_prev = items.some((it) => it.id < firstId);
        has_next = items.some((it) => it.id > lastId);
      }

      return Response.json(
        { items: page, page_info: { has_next, has_prev, start_cursor, end_cursor } },
        { status: 200 },
      );
    }

    return Response.json({ error: "not_found" }, { status: 404 });
  },
});

console.log(`bidirectional-cursor reference listening on ${port}`);
BUN_BENCH_SOLUTION_EOF
